import React, { useState } from "react";
import FriendList from "./FriendList";
import NotificationList from "./NotificationList";

export default function HomePage() {
  const [screen, setScreen] = useState("newfeed");
  const [input2, onChangeInput2] = useState('');
  const [toast, setToast] = useState(null);

  const [comments, setComments] = useState([
    { input: '', list: [], likes: 0 },
    { input: '', list: [], likes: 0 },
    { input: '', list: [], likes: 0 },
  ]);

  // Chat state
  const [chatInput, setChatInput] = useState("");
  const [chatMessages, setChatMessages] = useState([]);

  const showToast = (message) => {
    setToast(message);
    setTimeout(() => setToast(null), 2500);
  };

  const sendChatMessage = (sender) => {
    if (chatInput.trim() === "") return;
    setChatMessages([...chatMessages, { text: chatInput, sender }]);
    setChatInput("");
  };

  // Nếu không phải newfeed
  if (screen === "friends") return <FriendList goBack={() => setScreen("newfeed")} />;
  if (screen === "notifications") return <NotificationList goBack={() => setScreen("newfeed")} />;

  return (
    <div className="flex min-h-screen bg-gray-100">
      <div className="flex-1 ml-[72px] flex flex-col">
        {/* Header */}
        <div className="fixed top-0 left-0 right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50">
          <span className="text-xl font-bold">HomePage</span>
        </div>

        {/* Feed scrollable */}
        <div className="mt-[80px] px-6 flex flex-col items-center gap-6">

          {/* Input đăng bài (demo) */}
          <div className="flex items-center bg-[#A2D3FF] py-3 px-6 rounded-[10px] w-full max-w-[1000px]">
            <input
              placeholder="Hôm nay bạn thế nào chia sẻ với tui đi!!"
              value={input2}
              onChange={(e) => onChangeInput2(e.target.value)}
              className="text-black bg-[#F6FEFF] text-xl flex-1 py-2 px-4 rounded-[50px] border-0"
            />
            <button
              className="ml-4 bg-blue-400 text-white px-4 py-2 rounded-lg"
              onClick={() => {
                if (input2.trim() !== "") {
                  showToast(`Bạn vừa gửi: "${input2}"`);
                  onChangeInput2('');
                }
              }}
            >
              Gửi
            </button>
          </div>
        </div>

        {/* --- Chat Box 2 người --- */}
        <div className="fixed bottom-5 right-5 w-[350px] bg-white border border-gray-300 rounded-lg shadow-lg flex flex-col">
          <div className="bg-blue-500 text-white px-4 py-2 rounded-t-lg font-semibold">
            Chat với Friend
          </div>

          <div className="flex-1 p-2 flex flex-col gap-2 max-h-[300px] overflow-y-auto">
            {chatMessages.map((msg, idx) => (
              <div
                key={idx}
                className={`max-w-[80%] px-3 py-1 rounded-lg text-sm ${
                  msg.sender === "You" ? "bg-blue-400 text-white self-end" : "bg-gray-200 text-black self-start"
                }`}
              >
                <span className="font-semibold">{msg.sender}: </span>{msg.text}
              </div>
            ))}
          </div>

          <div className="flex border-t border-gray-300">
            <input
              className="flex-1 px-2 py-1 outline-none"
              placeholder="Nhập tin nhắn..."
              value={chatInput}
              onChange={(e) => setChatInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") sendChatMessage("You");
              }}
            />
            <button
              className="px-4 bg-blue-500 text-white rounded-r-lg"
              onClick={() => sendChatMessage("You")}
            >
              Gửi
            </button>
            <button
              className="px-4 bg-green-500 text-white rounded-r-lg"
              onClick={() => sendChatMessage("Friend")}
            >
              Friend
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes slideDown {
          0% { opacity: 0; transform: translateY(-20px); }
          100% { opacity: 1; transform: translateY(0); }
        }
        .animate-slide-down { animation: slideDown 0.3s ease-out; }
      `}</style>
    </div>
  );
}
